#!/usr/bin/env python3
"""
Bug #1891: jax.jit (XLA) produces wrong output vs PyTorch eager reference.

Patterns    : [['normalization', 'reduce_logsum_last'], ['attention', 'matmul_4d_batch'], ['constant', 'mul_self_to_pow'], ['attention', 'matmul_4d_batch'], ['layout', 'resize_linear_aligncorners'], ['fusion', 'conv_asym_pad_bn']]
Dependencies: numpy jax
Run         : python unique_1891.py  →  exit 0 = BUG REPRODUCED
"""
import sys
import numpy as np
import jax, jax.numpy as jnp
from jax import lax
import jax.scipy.special

# ── Model weights ─────────────────────────────────────────────────────────────
_w0 = np.frombuffer(bytes.fromhex("00000000"), dtype=np.float32).reshape([1])
_w1 = np.frombuffer(bytes.fromhex("6f12833a"), dtype=np.float32).reshape([1])
_w2 = np.frombuffer(bytes.fromhex(""), dtype=np.float32).reshape([1, 1, 32, 32])
_w3 = np.frombuffer(bytes.fromhex("bd378635"), dtype=np.float32).reshape([1])
_w4 = np.frombuffer(bytes.fromhex(""), dtype=np.float32).reshape([1, 3, 32, 32])
_w5 = np.frombuffer(bytes.fromhex(""), dtype=np.float32).reshape([1, 1, 32, 32])
_w6 = np.frombuffer(bytes.fromhex(""), dtype=np.float32).reshape([0])
_w7 = np.frombuffer(bytes.fromhex("0000803f0000803f0000004000000040"), dtype=np.float32).reshape([4])
_w8 = np.frombuffer(bytes.fromhex("00000000000000000000803f000000000000000000000000000000000000803f"), dtype=np.float32).reshape([8])
_w9 = np.frombuffer(bytes.fromhex(""), dtype=np.float32).reshape([64, 3, 3, 3])
_w10 = np.frombuffer(bytes.fromhex(""), dtype=np.float32).reshape([64])
_w11 = np.frombuffer(bytes.fromhex(""), dtype=np.float32).reshape([64])
_w12 = np.frombuffer(bytes.fromhex(""), dtype=np.float32).reshape([64])
_w13 = np.frombuffer(bytes.fromhex(""), dtype=np.float32).reshape([64])
_w14 = np.frombuffer(bytes.fromhex(""), dtype=np.float32).reshape([64])

# ── Triggering input ─────────────────────────────────────────────────────────
INPUT = np.frombuffer(bytes.fromhex(""), dtype=np.float32).reshape([1, 3, 32, 32])  # input "model_input"

EXPECTED = np.frombuffer(bytes.fromhex(""), dtype=np.float32)  # pytorch_eager reference


# ── Model computation (translated from ONNX) ──────────────────────────────────
def model(x):
    n0_redu_abs = jnp.abs(x)
    n0_redu_sh = n0_redu_abs + _w1
    n0_redu_red = jnp.log(jnp.sum(n0_redu_sh, axis=(-1,), keepdims=True))
    n0_redu_z = x * _w0
    n0_redu_out = n0_redu_z + n0_redu_red
    n100_mm4d_out = jnp.matmul(n0_redu_out, _w2)
    n200_msp_sq = n100_mm4d_out * n100_mm4d_out
    n200_msp_add = n200_msp_sq + _w3
    n200_msp_sq2 = jnp.sqrt(n200_msp_add)
    n200_msp_out = n200_msp_sq2 * _w4
    n300_mm4d_out = jnp.matmul(n200_msp_out, _w5)
    n400_resi_out = (lambda _x, _sc: jnp.transpose(jax.image.resize(jnp.transpose(_x,(0,2,3,1)), (int(_x.shape[0]), int(_x.shape[2]*_sc[2]), int(_x.shape[3]*_sc[3]), int(_x.shape[1])), method='linear'), (0,3,1,2)))(n300_mm4d_out, _w7)
    n500_capbn_pad = jnp.pad(n400_resi_out, [(int(_w8[k]), int(_w8[k+len(n400_resi_out.shape)])) for k in range(len(n400_resi_out.shape))], mode='constant')
    n500_capbn_cv = (lax.conv_general_dilated(n500_capbn_pad, _w9, window_strides=[1, 1], padding=((0, 0), (0, 0)), lhs_dilation=(1,1), rhs_dilation=[1, 1], dimension_numbers=('NCHW','OIHW','NCHW'), feature_group_count=1) + jnp.reshape(_w10, [1,-1,1,1]))
    n500_capbn_out = (lambda _x, _s, _b, _m, _v: jnp.reshape(_s, [1,-1]+[1]*(_x.ndim-2)) * ((_x - jnp.reshape(_m, [1,-1]+[1]*(_x.ndim-2))) / jnp.sqrt(jnp.reshape(_v, [1,-1]+[1]*(_x.ndim-2)) + np.float32(9.999999747378752e-06))) + jnp.reshape(_b, [1,-1]+[1]*(_x.ndim-2)))(n500_capbn_cv, _w11, _w12, _w13, _w14)
    return jnp.asarray(n500_capbn_out, dtype=jnp.float32)


if __name__ == "__main__":
    x_jax = jnp.array(INPUT)
    out = np.array(jax.jit(model)(x_jax), dtype=np.float32).ravel()

    diff = float(np.linalg.norm(EXPECTED.astype(np.float64) - out.astype(np.float64))
                 / (np.linalg.norm(EXPECTED.astype(np.float64)) + 1e-8))
    print(f"expected (pytorch_eager): {EXPECTED[:6]}")
    print(f"actual   (jax.jit/XLA) : {out[:6]}")
    print(f"rel L2 : {diff:.4e}")
    if diff > 0.001:
        print("BUG REPRODUCED")
        sys.exit(0)
    sys.exit(1)
